#include <bits/stdc++.h>
#define zrq0331
#define int long long
using namespace std;
int n;
int tot;
int ans;
int p[1000005];
int phi[10000005];
int sum[10000005];
bool flg[10000005];
void prime (int n) {
	phi[1]=1;
	for (int i = 2; i <= n; i++) {
		if (!flg[i]) {
			p[++tot] = i;
			phi[i] = i - 1;
		}
		for (int j = 1; j <= tot && i * p[j] <= n; ++j) {
			flg[i * p[j]] = 1;
			if (i % p[j] == 0) {
				phi[i * p[j]] = phi[i] * p[j];
				break;
			} else {
				phi[i * p[j]] = phi[i] * phi[p[j]];
			}
		}
	}
	for (int i = 1; i <= n; i++) {
		sum[i] = sum[i - 1] + phi[i];
	}
}
signed main() {
	cin >> n;
	prime(n);
	for (int i = 1; i <= tot; i++) {
		ans += 2 * sum[n / p[i]] - 1;
	}
	cout << ans;
	return 0;
}
